package unverified;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairAliasAwareInvocationTestSupport.*;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair5998DifferenceFindingTest {

    private final ClonePair5998 subject = new ClonePair5998();

    /**
     * Generated by Codex (GPT-5).
     * separating case: shared_0_1 ["sharedValue", "sharedValue"]
     */
    @Test
    void methodsDisagreeOnGeneratedInput() {
        InvocationOutcome method1Outcome = captureWithTimeout(values -> subject.method1((java.util.Vector) values[0], (java.util.Vector) values[1]), 1000L, buildMethod1Inputs());
        InvocationOutcome method2Outcome = captureWithTimeout(values -> subject.method2((java.util.Vector) values[0], (java.util.Vector) values[1]), 1000L, buildMethod2Inputs());

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "java.util.Vector[String(YWxpYXM=)]",
            null,
            "java.lang.Object[][java.util.Vector[String(YWxpYXM=)],java.util.Vector[String(YWxpYXM=)]]",
            "java.lang.Object[][java.util.Vector[String(YWxpYXM=)],java.util.Vector[String(YWxpYXM=)]]"
        );
        assertTextEquals("originalInputsSnapshot", "java.lang.Object[][java.util.Vector[String(YWxpYXM=)],java.util.Vector[String(YWxpYXM=)]]", method2Outcome.originalInputsSnapshot);
        assertDifferent(method1Outcome, method2Outcome);
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }

    private Object[] buildMethod1Inputs() {
        java.util.Vector sharedValue = vectorOfStrings("alias");
        return new Object[]{sharedValue, sharedValue};
    }

    private Object[] buildMethod2Inputs() {
        java.util.Vector sharedValue = vectorOfStrings("alias");
        return new Object[]{sharedValue, sharedValue};
    }

}
